// ═══════════════════════════════════════════════════════════════════════════
// ТОЧКА ВХОДА
// ═══════════════════════════════════════════════════════════════════════════
function trigger(source, value, variables, options, context) {
  try {
    setupBackupCron(variables, options);

    if (!variables._loaded) {
      variables._loaded     = true;
      variables.deviceLabel = getDeviceLabel(options);
      persistLoad(variables, options);
    }

    // Сброс через опцию resetNow
    if (options.resetNow === true) {
      resetFilter(variables, options);
      options.resetNow = false;
      return;
    }

    onDeviceChange(variables, options);
  } catch(e) {
    console.error("[Фильтр] trigger: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// СТРАХОВОЧНЫЙ CRON — каждый час фиксирует накопленное
// ═══════════════════════════════════════════════════════════════════════════
function setupBackupCron(variables, options) {
  if (variables.cronJob) return;
  variables.cronJob = Cron.schedule("0 0 * * * *", function() {
    try {
      if (variables.intervalActive && variables.intervalStart) {
        var now = Date.now();
        var elapsedMs = now - variables.intervalStart;
        if (elapsedMs > 10000) {
          accumulateInterval(elapsedMs / 3600000, variables.intervalMode, variables.intervalSpeed, variables, options);
          variables.intervalStart = now;
        }
      }
      logStatus(variables, options);
    } catch(e) {
      console.error("[Фильтр] cron: " + e.message);
    }
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// ОБРАБОТЧИК ИЗМЕНЕНИЯ СОСТОЯНИЯ РЕКУПЕРАТОРА
// ═══════════════════════════════════════════════════════════════════════════
function onDeviceChange(variables, options) {
  var now   = Date.now();
  var state = getRecuperatorState(options);
  if (!state) return;

  // Закрываем предыдущий интервал
  if (variables.intervalActive && variables.intervalStart) {
    var elapsedMs = now - variables.intervalStart;
    if (elapsedMs > 10000) {
      accumulateInterval(elapsedMs / 3600000, variables.intervalMode, variables.intervalSpeed, variables, options);
    }
  }

  // Открываем новый интервал или закрываем
  if (state.active) {
    variables.intervalActive = true;
    variables.intervalStart  = now;
    variables.intervalMode   = state.workmode;
    variables.intervalSpeed  = state.speed;
    if (options.debugMode) {
      console.info("[Фильтр] [" + variables.deviceLabel + "] Новый интервал: " + modeRu(state.workmode) + " скорость=" + state.speed);
    }
  } else {
    variables.intervalActive = false;
    variables.intervalStart  = undefined;
    variables.intervalMode   = undefined;
    variables.intervalSpeed  = undefined;
    if (options.debugMode) {
      console.info("[Фильтр] [" + variables.deviceLabel + "] Прибор выключен, интервал закрыт");
    }
  }

  logStatus(variables, options);
}

// ═══════════════════════════════════════════════════════════════════════════
// НАКОПЛЕНИЕ ДАННЫХ ЗА ИНТЕРВАЛ
// ═══════════════════════════════════════════════════════════════════════════
function accumulateInterval(hours, workmode, speed, variables, options) {
  var flow   = getFlowBySpeedAndMode(speed, workmode, options);
  var m3Tick = flow * hours;

  if (isIntakeMode(workmode)) {
    variables.m3Intake  = (variables.m3Intake  || 0) + m3Tick;
  } else if (isExhaustMode(workmode)) {
    variables.m3Exhaust = (variables.m3Exhaust || 0) + m3Tick;
  } else {
    variables.m3Intake  = (variables.m3Intake  || 0) + m3Tick * 0.5;
    variables.m3Exhaust = (variables.m3Exhaust || 0) + m3Tick * 0.5;
    variables.m3Recup   = (variables.m3Recup   || 0) + m3Tick;
  }
  variables.m3Total = (variables.m3Total || 0) + m3Tick;

  // Реальный ресурс с поправками
  var coeffs  = calcCoeffs(options);
  var divisor = coeffs.area * coeffs.floor * coeffs.season;
  var f7Real     = Math.round((options.f7BaseResourceM3     || 60000) / divisor);
  var carbonReal = Math.round((options.carbonBaseResourceM3 || 30000) / divisor);

  // Износ F7 — весь поток с коэфф. режима
  var modeCoeff = getModeCoeffF7(workmode);
  var f7EffM3   = m3Tick * modeCoeff;
  variables.wearF7 = Math.min(100, (variables.wearF7 || 0) + (f7EffM3 / f7Real * 100));

  // Износ угля — только приток
  var carbonM3 = 0;
  if (isIntakeMode(workmode))        { carbonM3 = m3Tick; }
  else if (!isExhaustMode(workmode)) { carbonM3 = m3Tick * 0.5; }
  variables.wearCarbon = Math.min(100, (variables.wearCarbon || 0) + (carbonM3 / carbonReal * 100));

  if (options.debugMode) {
    var mins = Math.round(hours * 60);
    console.info("[Фильтр] [" + variables.deviceLabel + "] Интервал: " +
      modeRu(workmode) + " | скор." + speed +
      " | " + mins + " мин" +
      " | +" + m3Tick.toFixed(1) + " м³" +
      " | F7 +" + (f7EffM3 / f7Real * 100).toFixed(3) + "%" +
      " | Уголь +" + (carbonM3 / carbonReal * 100).toFixed(3) + "%"
    );
  }

  persistSave(variables, options);
}

// ═══════════════════════════════════════════════════════════════════════════
// СОХРАНЕНИЕ ДАННЫХ В ХАРАКТЕРИСТИКИ УСТРОЙСТВА
// Каждый сервис выбирается пользователем из списка через options.svcXxx
// После записи — контрольное чтение для верификации
// ═══════════════════════════════════════════════════════════════════════════
function persistSave(variables, options) {
  try {
    var wF7     = Math.min(100, Math.round((variables.wearF7     || 0) * 1000) / 1000);
    var wCarbon = Math.min(100, Math.round((variables.wearCarbon || 0) * 1000) / 1000);
    var worst   = Math.max(wF7, wCarbon);

    // Сохраняем накопители м³ через C_GasMeter (UUID из options)
    var dl = variables.deviceLabel || "?";
    saveToGasMeter(options.svcM3Total,    variables.m3Total   || 0, "м³ всего",    options, dl);
    saveToGasMeter(options.svcM3Intake,   variables.m3Intake  || 0, "м³ приток",   options, dl);
    saveToGasMeter(options.svcM3Exhaust,  variables.m3Exhaust || 0, "м³ вытяжка",  options, dl);
    saveToGasMeter(options.svcM3Recup,    variables.m3Recup   || 0, "м³ рекуп",    options, dl);

    // Сохраняем износ через C_GasMeter
    saveToGasMeter(options.svcWearF7,     wF7,     "износ F7",    options, dl);
    saveToGasMeter(options.svcWearCarbon, wCarbon, "износ уголь", options, dl);

    // Обновляем отображение FilterMaintenance (read-only в HomeKit, только текущая сессия)
    saveToFilterMaintenance(options.svcFilterF7,      Math.round(100 - wF7),     wF7 >= 85,     options);
    saveToFilterMaintenance(options.svcFilterCarbon,  Math.round(100 - wCarbon), wCarbon >= 85, options);
    saveToFilterMaintenance(options.svcFilterGeneral, Math.round(100 - worst),   worst >= 85,   options);

  } catch(e) {
    console.error("[Фильтр] persistSave: " + e.message);
  }
}

function saveToGasMeter(uuid, value, label, options, deviceLabel) {
  try {
    var svc = getService(uuid);
    if (!svc) return;
    var c = svc.getCharacteristic(HC.C_CubicMeter);
    if (!c) return;
    var valRounded = Math.round(value * 100) / 100;
    c.setValue(valRounded);
    var readBack = c.getValue();
    if (options.debugMode) {
      console.info("[Фильтр SAVE] [" + (deviceLabel || "?") + "] " + label + ": записано=" + valRounded + " прочитано=" + readBack);
    }
  } catch(e) {
    console.error("[Фильтр] saveToGasMeter(" + label + "): " + e.message);
  }
}

function saveToFilterMaintenance(uuid, lifeLevel, needChange, options) {
  try {
    var svc = getService(uuid);
    if (!svc) return;
    var ll = svc.getCharacteristic(HC.FilterLifeLevel);
    var fc = svc.getCharacteristic(HC.FilterChangeIndication);
    if (ll) ll.setValue(Math.max(0, lifeLevel));
    if (fc) fc.setValue(needChange ? 1 : 0);
  } catch(e) {
    console.error("[Фильтр] saveToFilterMaintenance: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ВОССТАНОВЛЕНИЕ ДАННЫХ ИЗ ХАРАКТЕРИСТИК УСТРОЙСТВА
// ═══════════════════════════════════════════════════════════════════════════
function persistLoad(variables, options) {
  try {
    var loaded = false;

    var m3Total   = readFromGasMeter(options.svcM3Total,    "м³ всего");
    var m3Intake  = readFromGasMeter(options.svcM3Intake,   "м³ приток");
    var m3Exhaust = readFromGasMeter(options.svcM3Exhaust,  "м³ вытяжка");
    var m3Recup   = readFromGasMeter(options.svcM3Recup,    "м³ рекуп");
    var wearF7    = readFromGasMeter(options.svcWearF7,     "износ F7");
    var wearCarbon = readFromGasMeter(options.svcWearCarbon, "износ уголь");

    if (m3Total   !== null) { variables.m3Total    = m3Total;   loaded = true; }
    if (m3Intake  !== null) { variables.m3Intake   = m3Intake;  loaded = true; }
    if (m3Exhaust !== null) { variables.m3Exhaust  = m3Exhaust; loaded = true; }
    if (m3Recup   !== null) { variables.m3Recup    = m3Recup;   loaded = true; }
    if (wearF7    !== null) { variables.wearF7     = wearF7;    loaded = true; }
    if (wearCarbon !== null){ variables.wearCarbon = wearCarbon; loaded = true; }

    if (loaded) {
      // Дней с установки
      var daysSince = calcDaysSince(options.filterInstalledDate);
      console.info(
        "[Фильтр] [" + (variables.deviceLabel || "?") + "] ♻️ Восстановлено из устройства:\n" +
        "  Приток=" + (variables.m3Intake  || 0).toFixed(1) + " м³\n" +
        "  Вытяжка=" + (variables.m3Exhaust || 0).toFixed(1) + " м³\n" +
        "  Рекуперация=" + (variables.m3Recup || 0).toFixed(1) + " м³\n" +
        "  Всего=" + (variables.m3Total || 0).toFixed(1) + " м³\n" +
        "  F7=" + (variables.wearF7 || 0).toFixed(3) + "%\n" +
        "  Уголь=" + (variables.wearCarbon || 0).toFixed(3) + "%\n" +
        "  Дата=" + (options.filterInstalledDate || "?") + " (" + daysSince + " дней)"
      );
    }
  } catch(e) {
    console.error("[Фильтр] persistLoad: " + e.message);
  }
}

function readFromGasMeter(uuid, label) {
  try {
    var svc = getService(uuid);
    if (!svc) return null;
    var c = svc.getCharacteristic(HC.C_CubicMeter);
    if (!c) return null;
    var val = c.getValue();
    if (val === null || val === undefined) return null;
    return val;
  } catch(e) {
    console.error("[Фильтр] readFromGasMeter(" + label + "): " + e.message);
    return null;
  }
}



