function resetFilter(variables, options) {
  variables.m3Total    = 0;
  variables.m3Intake   = 0;
  variables.m3Exhaust  = 0;
  variables.m3Recup    = 0;
  variables.wearF7     = 0;
  variables.wearCarbon = 0;
  variables.intervalStart  = undefined;
  variables.intervalActive = false;

  // Обновляем дату установки на сегодня
  var today = new Date();
  var dd   = today.getDate()        < 10 ? "0" + today.getDate()        : "" + today.getDate();
  var mm   = (today.getMonth() + 1) < 10 ? "0" + (today.getMonth() + 1) : "" + (today.getMonth() + 1);
  var yyyy = today.getFullYear();
  options.filterInstalledDate = dd + "-" + mm + "-" + yyyy;

  persistSave(variables, options);
  console.info("[Фильтр] [" + variables.deviceLabel + "] ✅ Счётчик сброшен. Новая дата установки: " + options.filterInstalledDate);
}

// ═══════════════════════════════════════════════════════════════════════════
// СТАТУС В ЛОГ
// ═══════════════════════════════════════════════════════════════════════════
function logStatus(variables, options) {
  if (!options.debugMode) return;
  var coeffs  = calcCoeffs(options);
  var divisor = coeffs.area * coeffs.floor * coeffs.season;
  var f7Real     = Math.round((options.f7BaseResourceM3     || 60000) / divisor);
  var carbonReal = Math.round((options.carbonBaseResourceM3 || 30000) / divisor);
  var daysSince  = calcDaysSince(options.filterInstalledDate);

  var nowInfo = "прибор выключен";
  if (variables.intervalActive && variables.intervalStart) {
    var elH  = (Date.now() - variables.intervalStart) / 3600000;
    var flow = getFlowBySpeedAndMode(variables.intervalSpeed || 1, variables.intervalMode || "inflow", options);
    nowInfo = modeRu(variables.intervalMode) +
      " | скор." + variables.intervalSpeed +
      " | " + Math.round(elH * 60) + " мин" +
      " | ~" + (flow * elH).toFixed(1) + " м³";
  }

  console.info(
    "[Фильтр STATUS] [" + variables.deviceLabel + "]" +
    " F7=" + (variables.wearF7 || 0).toFixed(2) + "%" +
    " | Уголь=" + (variables.wearCarbon || 0).toFixed(2) + "%" +
    " | Приток=" + (variables.m3Intake  || 0).toFixed(1) + "м³" +
    " | Вытяжка=" + (variables.m3Exhaust || 0).toFixed(1) + "м³" +
    " | Всего=" + (variables.m3Total || 0).toFixed(1) + "м³" +
    " | F7ресурс=" + f7Real + "м³" +
    " | УгольРесурс=" + carbonReal + "м³" +
    " | Дней=" + daysSince +
    " | Сейчас=" + nowInfo
  );
  console.info(
    "[Фильтр КОЭФФ] [" + variables.deviceLabel + "]" +
    " Район=" + coeffs.area.toFixed(2) +
    " | Этаж=" + coeffs.floor.toFixed(2) +
    " | Сезон=" + coeffs.season.toFixed(2) +
    " | Делитель=" + divisor.toFixed(3)
  );
}

