// Получить сервис по UUID из options (формат "accId.svcId")
function getService(uuid) {
  if (!uuid || uuid === "") return null;
  try {
    var parts = uuid.split(".");
    return Hub.getAccessory(parts[0]).getService(parts[1]);
  } catch(e) {
    return null;
  }
}

function getRecuperatorState(options) {
  try {
    var svc = getService(options.recuperatorFanService);
    if (!svc) return null;
    var activeChar = svc.getCharacteristic(HC.Active);
    var speedChar  = svc.getCharacteristic(HC.RotationSpeed);
    var active = activeChar ? (activeChar.getValue() === 1) : false;
    var speed  = speedChar  ? Math.round(speedChar.getValue()) : 1;
    var workmode = "inflow";
    try {
      var acc = svc.getAccessory();
      acc.getServices().forEach(function(s) {
        if (s.getType() === HS.Television) {
          var modeChar = s.getCharacteristic(HC.ActiveIdentifier);
          if (modeChar) {
            var mm = { 1:"inflow", 2:"inflow_max", 3:"recuperator", 4:"winter", 5:"outflow", 6:"outflow_max", 7:"night" };
            workmode = mm[modeChar.getValue()] || "inflow";
          }
        }
      });
    } catch(e) {}
    return { active: active, speed: speed, workmode: workmode };
  } catch(e) {
    console.error("[Фильтр] getRecuperatorState: " + e.message);
    return null;
  }
}

function getDeviceLabel(options) {
  try {
    var svc = getService(options.recuperatorFanService);
    if (!svc) return "?";
    var acc  = svc.getAccessory();
    var room = acc.getRoom ? acc.getRoom() : null;
    return (room ? room.getName() + " / " : "") + acc.getName();
  } catch(e) { return "?"; }
}

function getFlowBySpeedAndMode(speed, workmode, options) {
  var isRecup = (workmode === "recuperator" || workmode === "winter" || workmode === "night");
  var map = isRecup ? {
    1: options.flowRecupSpd1 || 20, 2: options.flowRecupSpd2 || 32,
    3: options.flowRecupSpd3 || 40, 4: options.flowRecupSpd4 || 45,
    5: options.flowRecupSpd5 || 50, 6: options.flowRecupSpd6 || 55,
    7: options.flowRecupSpd7 || 60
  } : {
    1: options.flowIntakeSpd1 || 40, 2: options.flowIntakeSpd2 || 65,
    3: options.flowIntakeSpd3 || 80, 4: options.flowIntakeSpd4 || 90,
    5: options.flowIntakeSpd5 || 100, 6: options.flowIntakeSpd6 || 110,
    7: options.flowIntakeSpd7 || 120
  };
  return map[speed] || map[3];
}

function getModeCoeffF7(workmode) {
  var map = {
    "inflow": 1.00, "inflow_max": 1.30,
    "recuperator": 1.00, "winter": 1.00,
    "outflow": 0.00, "outflow_max": 0.00,
    "night": 0.50
  };
  return map[workmode] !== undefined ? map[workmode] : 0.65;
}

function calcCoeffs(options) {
  var areaMap = { "quiet": 0.80, "road_far": 1.00, "road_near": 1.25, "road_adj": 1.55, "industrial": 1.70 };
  var area  = areaMap[options.areaType] || 1.00;
  var floor = parseInt(options.floorNumber, 10) || 6;
  var floorCoeff = floor <= 2 ? 1.15 : floor <= 5 ? 1.05 : floor <= 9 ? 1.00 : floor <= 15 ? 0.95 : 0.90;
  var month  = new Date().getMonth() + 1;
  var season = month >= 3 && month <= 5 ? 1.10 : month >= 6 && month <= 8 ? 1.05 : month >= 9 && month <= 11 ? 1.00 : 0.95;
  return { area: area, floor: floorCoeff, season: season };
}

function calcDaysSince(dateStr) {
  try {
    var parts = (dateStr || "").split("-");
    var d;
    if (parts.length === 3 && parts[2].length === 4) {
      d = new Date(parts[2] + "-" + parts[1] + "-" + parts[0]);
    } else {
      d = new Date(dateStr);
    }
    return Math.floor((Date.now() - d.getTime()) / 86400000);
  } catch(e) { return 0; }
}

function isIntakeMode(w)  { return w === "inflow" || w === "inflow_max"; }
function isExhaustMode(w) { return w === "outflow" || w === "outflow_max"; }

function modeRu(w) {
  return { inflow:"Приток", inflow_max:"Приток MAX", recuperator:"Рекуп.лето",
           winter:"Рекуп.зима", outflow:"Вытяжка", outflow_max:"Вытяжка MAX", night:"Ночной" }[w] || w;
}

function getServiceList(serviceTypes, charType) {
  var result   = [{ name: { ru: "Не выбрано", en: "Not selected" }, value: "" }];
  var unsorted = [];
  Hub.getAccessories().forEach(function(acc) {
    acc.getServices().filter(function(s) {
      return serviceTypes.indexOf(s.getType()) >= 0;
    }).forEach(function(svc) {
      var c = svc.getCharacteristic(charType);
      if (c) {
        var room  = acc.getRoom ? acc.getRoom() : null;
        var rName = room ? room.getName() : "";
        var aName = acc.getName();
        var sName = svc.getName();
        var label = (rName ? rName + " → " : "") + aName + (aName !== sName ? " " + sName : "") + " (" + svc.getUUID() + ")";
        unsorted.push({ name: { ru: label, en: label }, value: svc.getUUID() });
      }
    });
  });
  unsorted.sort(function(a, b) { return a.name.ru.localeCompare(b.name.ru); });
  unsorted.forEach(function(s) { result.push(s); });
  return result;
}
